import React from 'react';

const styles = {
  header: {
    borderBottom: '1px solid var(--border)',
    background: 'rgba(5,8,16,0.95)',
    backdropFilter: 'blur(12px)',
    position: 'sticky',
    top: 0,
    zIndex: 100,
  },
  inner: {
    maxWidth: 900,
    margin: '0 auto',
    padding: '1rem 1.5rem',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    flexWrap: 'wrap',
    gap: '1rem',
  },
  logo: {
    display: 'flex',
    alignItems: 'center',
    gap: '0.75rem',
  },
  shield: {
    width: 38,
    height: 38,
    background: 'linear-gradient(135deg, #1e3a8a, #7e22ce)',
    borderRadius: 8,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '1.2rem',
    boxShadow: '0 0 20px rgba(0,212,255,0.3)',
  },
  title: {
    fontFamily: 'var(--font-display)',
    fontWeight: 900,
    fontSize: '1.15rem',
    letterSpacing: '0.05em',
    color: 'var(--neon-blue)',
    textTransform: 'uppercase',
  },
  sub: {
    fontFamily: 'var(--font-mono)',
    fontSize: '0.65rem',
    color: 'var(--text-dim)',
    letterSpacing: '0.1em',
  },
  nav: { display: 'flex', gap: '0.5rem' },
};

function NavBtn({ label, active, onClick }) {
  return (
    <button
      onClick={onClick}
      style={{
        padding: '0.45rem 1.1rem',
        borderRadius: 6,
        border: active ? '1px solid var(--neon-blue)' : '1px solid var(--border)',
        background: active ? 'rgba(0,212,255,0.12)' : 'transparent',
        color: active ? 'var(--neon-blue)' : 'var(--text-secondary)',
        fontFamily: 'var(--font-display)',
        fontWeight: 600,
        fontSize: '0.85rem',
        cursor: 'pointer',
        letterSpacing: '0.05em',
        textTransform: 'uppercase',
        transition: 'all 0.2s',
      }}
    >
      {label}
    </button>
  );
}

export default function Header({ page, setPage }) {
  return (
    <header style={styles.header}>
      <div style={styles.inner}>
        <div style={styles.logo}>
          <div style={styles.shield}>🛡️</div>
          <div>
            <div style={styles.title}>AI Firewall</div>
            <div style={styles.sub}>PROMPT SECURITY SYSTEM</div>
          </div>
        </div>
        <nav style={styles.nav}>
          <NavBtn label="⚡ Check Prompt" active={page === 'check'} onClick={() => setPage('check')} />
          <NavBtn label="📋 Logs"         active={page === 'logs'}  onClick={() => setPage('logs')} />
        </nav>
      </div>
    </header>
  );
}
